/* ============================================
   STACK & BITE — Landing Page Styles
   Edit the CSS variables below to retheme quickly
   ============================================ */

:root {
  /* Warm cafe & sandwich palette */
  --color-cream: #fff9f2;
  --color-cream-dark: #f5ebe0;
  --color-brown: #2c1810;
  --color-brown-soft: #5c4033;
  --color-amber: #d97706;
  --color-amber-dark: #b45309;
  --color-terracotta: #c45c26;
  --color-sage: #6b7c5e;

  /* UI */
  --color-white: #ffffff;
  --color-shadow: rgba(44, 24, 16, 0.12);
  --color-shadow-strong: rgba(44, 24, 16, 0.2);

  /* Typography */
  --font-body: "DM Sans", system-ui, sans-serif;
  --font-display: "Fraunces", Georgia, serif;

  /* Spacing scale — change one value to adjust rhythm sitewide */
  --space-xs: 0.5rem;
  --space-sm: 1rem;
  --space-md: 1.5rem;
  --space-lg: 2.5rem;
  --space-xl: 4rem;

  /* Layout */
  --container-width: 72rem;
  --header-height: 4.5rem;
  --radius-sm: 0.5rem;
  --radius-md: 1rem;
  --radius-lg: 1.5rem;
  --radius-full: 9999px;

  /* Transitions */
  --transition-fast: 0.2s ease;
  --transition-smooth: 0.35s cubic-bezier(0.4, 0, 0.2, 1);
}

/* ---------- Reset & base ---------- */
*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  scroll-behavior: smooth;
}

body {
  font-family: var(--font-body);
  font-size: 1rem;
  line-height: 1.6;
  color: var(--color-brown-soft);
  background-color: var(--color-cream);
  -webkit-font-smoothing: antialiased;
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

a {
  text-decoration: none;
  color: inherit;
}

ul {
  list-style: none;
}

/* Centered content wrapper — reuse on every section */
.container {
  width: 100%;
  max-width: var(--container-width);
  margin-inline: auto;
  padding-inline: var(--space-md);
}

/* ---------- Buttons ---------- */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-xs);
  padding: 0.75rem 1.5rem;
  font-family: var(--font-body);
  font-size: 0.9375rem;
  font-weight: 600;
  border-radius: var(--radius-full);
  border: 2px solid transparent;
  cursor: pointer;
  transition:
    background-color var(--transition-fast),
    color var(--transition-fast),
    border-color var(--transition-fast),
    transform var(--transition-fast),
    box-shadow var(--transition-fast);
}

.btn--primary {
  background: linear-gradient(135deg, var(--color-amber), var(--color-terracotta));
  color: var(--color-white);
  box-shadow: 0 4px 14px rgba(217, 119, 6, 0.35);
}

.btn--primary:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 20px rgba(217, 119, 6, 0.45);
}

.btn--outline {
  background: var(--color-white);
  color: var(--color-brown);
  border-color: var(--color-cream-dark);
}

.btn--outline:hover {
  border-color: var(--color-amber);
  color: var(--color-amber-dark);
  transform: translateY(-2px);
  box-shadow: 0 4px 12px var(--color-shadow);
}

.btn--lg {
  padding: 1rem 1.75rem;
  font-size: 1rem;
}

.btn--full {
  width: 100%;
}

/* ============================================
   NAVBAR
   ============================================ */
.header {
  position: sticky;
  top: 0;
  z-index: 100;
  height: var(--header-height);
  background: rgba(255, 249, 242, 0.85);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border-bottom: 1px solid transparent;
  transition:
    border-color var(--transition-smooth),
    box-shadow var(--transition-smooth);
}

/* Added when user scrolls — class toggled in script.js */
.header--scrolled {
  border-bottom-color: var(--color-cream-dark);
  box-shadow: 0 4px 24px var(--color-shadow);
}

.nav {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: var(--header-height);
  gap: var(--space-md);
}

.nav__logo {
  font-family: var(--font-display);
  font-size: 1.35rem;
  font-weight: 700;
  color: var(--color-brown);
  letter-spacing: -0.02em;
  flex-shrink: 0;
}

.nav__logo span {
  color: var(--color-amber);
}

.nav__menu {
  display: flex;
  align-items: center;
  gap: var(--space-lg);
}

.nav__link {
  font-size: 0.9375rem;
  font-weight: 500;
  color: var(--color-brown-soft);
  position: relative;
  padding: 0.25rem 0;
  transition: color var(--transition-fast);
}

.nav__link::after {
  content: "";
  position: absolute;
  left: 0;
  bottom: -2px;
  width: 0;
  height: 2px;
  background: var(--color-amber);
  border-radius: var(--radius-full);
  transition: width var(--transition-smooth);
}

.nav__link:hover,
.nav__link--active {
  color: var(--color-brown);
}

.nav__link:hover::after,
.nav__link--active::after {
  width: 100%;
}

.nav__order-btn {
  flex-shrink: 0;
}

/* Hidden on desktop — shown inside mobile drawer */
.nav__item--mobile-btn {
  display: none;
  width: 100%;
  margin-top: var(--space-sm);
}

/* Hamburger — hidden on desktop */
.nav__toggle {
  display: none;
  flex-direction: column;
  justify-content: center;
  gap: 5px;
  width: 2.5rem;
  height: 2.5rem;
  padding: 0.5rem;
  background: var(--color-white);
  border: 1px solid var(--color-cream-dark);
  border-radius: var(--radius-sm);
  cursor: pointer;
  transition: border-color var(--transition-fast);
}

.nav__toggle:hover {
  border-color: var(--color-amber);
}

.nav__toggle-bar {
  display: block;
  width: 100%;
  height: 2px;
  background: var(--color-brown);
  border-radius: var(--radius-full);
  transition:
    transform var(--transition-smooth),
    opacity var(--transition-smooth);
}

/* Animated X when menu is open */
.nav__toggle--active .nav__toggle-bar:nth-child(1) {
  transform: translateY(7px) rotate(45deg);
}

.nav__toggle--active .nav__toggle-bar:nth-child(2) {
  opacity: 0;
}

.nav__toggle--active .nav__toggle-bar:nth-child(3) {
  transform: translateY(-7px) rotate(-45deg);
}

/* ============================================
   HERO SECTION
   ============================================ */
.hero {
  /* Full viewport minus sticky header */
  min-height: calc(100vh - var(--header-height));
  min-height: calc(100dvh - var(--header-height));
  display: flex;
  align-items: center;
  padding-block: var(--space-lg);
  position: relative;
  overflow: hidden;
}

/* Subtle background texture */
.hero::before {
  content: "";
  position: absolute;
  inset: 0;
  background:
    radial-gradient(ellipse 80% 60% at 90% 20%, rgba(217, 119, 6, 0.08), transparent),
    radial-gradient(ellipse 60% 50% at 10% 80%, rgba(107, 124, 94, 0.06), transparent);
  pointer-events: none;
}

.hero__container {
  display: grid;
  grid-template-columns: 1fr 1fr;
  align-items: center;
  gap: var(--space-xl);
  position: relative;
  z-index: 1;
}

.hero__badge {
  display: inline-block;
  font-size: 0.8125rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--color-sage);
  background: rgba(107, 124, 94, 0.12);
  padding: 0.4rem 0.9rem;
  border-radius: var(--radius-full);
  margin-bottom: var(--space-md);
}

.hero__title {
  font-family: var(--font-display);
  font-size: clamp(2.5rem, 5vw, 3.75rem);
  font-weight: 800;
  line-height: 1.1;
  color: var(--color-brown);
  letter-spacing: -0.03em;
  margin-bottom: var(--space-md);
}

.hero__description {
  font-size: 1.125rem;
  line-height: 1.7;
  max-width: 32rem;
  margin-bottom: var(--space-lg);
  color: var(--color-brown-soft);
}

.hero__buttons {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-sm);
  margin-bottom: var(--space-lg);
}

.hero__note {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
  font-size: 0.875rem;
  color: var(--color-brown-soft);
  opacity: 0.85;
}

.hero__note-dot {
  width: 8px;
  height: 8px;
  background: var(--color-sage);
  border-radius: var(--radius-full);
  animation: pulse 2s ease-in-out infinite;
}

@keyframes pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.4; }
}

/* ---------- Hero image column ---------- */
.hero__visual {
  position: relative;
  display: flex;
  justify-content: center;
  align-items: center;
}

.hero__image-wrapper {
  position: relative;
  width: min(100%, 28rem);
  aspect-ratio: 1;
  border-radius: var(--radius-lg);
  overflow: hidden;
  box-shadow:
    0 24px 48px var(--color-shadow-strong),
    0 0 0 8px var(--color-white);
  transition: transform var(--transition-smooth);
}

.hero__image-wrapper:hover {
  transform: scale(1.02) rotate(-1deg);
}

.hero__image {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.hero__image-glow {
  position: absolute;
  inset: -20%;
  background: radial-gradient(circle, rgba(217, 119, 6, 0.25), transparent 70%);
  z-index: -1;
  pointer-events: none;
}

/* Floating special card */
.hero__card {
  position: absolute;
  bottom: 8%;
  left: -4%;
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  background: var(--color-white);
  padding: var(--space-sm) var(--space-md);
  border-radius: var(--radius-md);
  box-shadow: 0 12px 32px var(--color-shadow);
  animation: float 4s ease-in-out infinite;
}

@keyframes float {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-8px); }
}

.hero__card-icon {
  font-size: 1.5rem;
}

.hero__card-title {
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--color-brown-soft);
}

.hero__card-text {
  font-family: var(--font-display);
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--color-brown);
}

/* ============================================
   RESPONSIVE — Tablet & Mobile
   ============================================ */
@media (max-width: 968px) {
  .hero__container {
    grid-template-columns: 1fr;
    gap: var(--space-lg);
    text-align: center;
  }

  .hero__description {
    margin-inline: auto;
  }

  .hero__buttons {
    justify-content: center;
  }

  .hero__note {
    justify-content: center;
  }

  .hero__visual {
    order: -1; /* Image above text on tablet/mobile */
  }

  .hero__card {
    left: 50%;
    transform: translateX(-50%);
    bottom: -5%;
  }

  @keyframes float {
    0%, 100% { transform: translateX(-50%) translateY(0); }
    50% { transform: translateX(-50%) translateY(-8px); }
  }
}

@media (max-width: 768px) {
  :root {
    --header-height: 4rem;
  }

  /* Mobile navigation drawer */
  .nav__toggle {
    display: flex;
  }

  .nav__order-btn {
    display: none;
  }

  .nav__menu {
    position: fixed;
    top: var(--header-height);
    left: 0;
    right: 0;
    flex-direction: column;
    align-items: stretch;
    gap: 0;
    background: var(--color-cream);
    border-bottom: 1px solid var(--color-cream-dark);
    padding: var(--space-md);
    box-shadow: 0 16px 32px var(--color-shadow);
    transform: translateY(-120%);
    opacity: 0;
    visibility: hidden;
    transition:
      transform var(--transition-smooth),
      opacity var(--transition-smooth),
      visibility var(--transition-smooth);
  }

  .nav__menu--open {
    transform: translateY(0);
    opacity: 1;
    visibility: visible;
  }

  .nav__item {
    border-bottom: 1px solid var(--color-cream-dark);
  }

  .nav__item:last-child {
    border-bottom: none;
  }

  .nav__link {
    display: block;
    padding: var(--space-sm) 0;
    font-size: 1.05rem;
  }

  .nav__item--mobile-btn {
    display: block;
    border-bottom: none;
    padding-top: var(--space-sm);
  }

  .hero {
    padding-block: var(--space-md);
  }

  .hero__buttons .btn {
    flex: 1;
    min-width: 140px;
  }
}

@media (max-width: 480px) {
  .hero__buttons {
    flex-direction: column;
    width: 100%;
  }

  .hero__buttons .btn {
    width: 100%;
  }
}

/**
 * Stack & Bite — Landing Page Scripts
 * Beginner-friendly: each section handles one feature.
 */

/* ---------- Mobile hamburger menu ---------- */
const navToggle = document.getElementById("nav-toggle");
const navMenu = document.getElementById("nav-menu");
const navLinks = document.querySelectorAll(".nav__link");

/**
 * Opens or closes the mobile navigation menu
 */
function toggleMenu() {
  const isOpen = navMenu.classList.toggle("nav__menu--open");
  navToggle.classList.toggle("nav__toggle--active", isOpen);
  navToggle.setAttribute("aria-expanded", isOpen);
  navToggle.setAttribute("aria-label", isOpen ? "Close menu" : "Open menu");

  // Prevent background scroll when menu is open on mobile
  document.body.style.overflow = isOpen ? "hidden" : "";
}

/**
 * Closes the menu (used when a link is clicked)
 */
function closeMenu() {
  navMenu.classList.remove("nav__menu--open");
  navToggle.classList.remove("nav__toggle--active");
  navToggle.setAttribute("aria-expanded", "false");
  navToggle.setAttribute("aria-label", "Open menu");
  document.body.style.overflow = "";
}

// Toggle menu when hamburger is clicked
navToggle.addEventListener("click", toggleMenu);

// Close menu when any nav link is clicked
navLinks.forEach((link) => {
  link.addEventListener("click", closeMenu);
});

// Close menu if user resizes to desktop width
window.addEventListener("resize", () => {
  if (window.innerWidth > 768) {
    closeMenu();
  }
});

/* ---------- Sticky navbar shadow on scroll ---------- */
const header = document.getElementById("header");

window.addEventListener("scroll", () => {
  if (window.scrollY > 20) {
    header.classList.add("header--scrolled");
  } else {
    header.classList.remove("header--scrolled");
  }
});

/* ---------- Active nav link highlight (optional) ---------- */
/**
 * Updates which nav link looks "active" based on scroll position.
 * Works once you add section IDs that match href="#menu", etc.
 */
const sections = document.querySelectorAll("section[id]");

function setActiveLink() {
  const scrollY = window.scrollY + 100;

  sections.forEach((section) => {
    const sectionTop = section.offsetTop;
    const sectionHeight = section.offsetHeight;
    const sectionId = section.getAttribute("id");

    if (scrollY >= sectionTop && scrollY < sectionTop + sectionHeight) {
      navLinks.forEach((link) => {
        link.classList.remove("nav__link--active");
        if (link.getAttribute("href") === `#${sectionId}`) {
          link.classList.add("nav__link--active");
        }
      });
    }
  });
}

window.addEventListener("scroll", setActiveLink);

