/* ============================================
   SHARED SECTION HEADER (Menu, About, Contact)
   ============================================ */
.section-header {
  text-align: center;
  max-width: 40rem;
  margin-inline: auto;
  margin-bottom: var(--space-lg);
}

.section-header__badge {
  display: inline-block;
  font-size: 0.8125rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--color-amber-dark);
  background: rgba(217, 119, 6, 0.12);
  padding: 0.4rem 0.9rem;
  border-radius: var(--radius-full);
  margin-bottom: var(--space-sm);
}

.section-header__title {
  font-family: var(--font-display);
  font-size: clamp(2rem, 4vw, 2.75rem);
  font-weight: 800;
  color: var(--color-brown);
  letter-spacing: -0.02em;
  margin-bottom: var(--space-sm);
}

.section-header__text {
  font-size: 1.0625rem;
  line-height: 1.7;
  color: var(--color-brown-soft);
}

/* ============================================
   MENU SECTION
   ============================================ */
.menu {
  padding-block: var(--space-xl);
  background: var(--color-white);
  position: relative;
}

/* Soft top edge blend from hero cream background */
.menu::before {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 4rem;
  background: linear-gradient(to bottom, var(--color-cream), var(--color-white));
  pointer-events: none;
}

.menu > .container {
  position: relative;
  z-index: 1;
}

/* Category filter pills */
.menu__filters {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: var(--space-xs);
  margin-bottom: var(--space-lg);
}

.menu__filter {
  font-family: var(--font-body);
  font-size: 0.875rem;
  font-weight: 600;
  color: var(--color-brown-soft);
  background: var(--color-cream);
  border: 2px solid transparent;
  padding: 0.5rem 1.1rem;
  border-radius: var(--radius-full);
  cursor: pointer;
  transition:
    background-color var(--transition-fast),
    color var(--transition-fast),
    border-color var(--transition-fast),
    transform var(--transition-fast);
}

.menu__filter:hover {
  color: var(--color-brown);
  border-color: var(--color-cream-dark);
}

.menu__filter--active {
  color: var(--color-white);
  background: linear-gradient(135deg, var(--color-amber), var(--color-terracotta));
  border-color: transparent;
  box-shadow: 0 4px 12px rgba(217, 119, 6, 0.3);
